#include <iostream>
#include <vector>
#include <sstream>
#include <string>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // Read all integers from stdin (space/newline separated)
    vector<int> a;
    int x;
    while (cin >> x) {
        a.push_back(x);
    }

    int n = (int)a.size();
    int peaks = 0, valleys = 0;

    for (int i = 1; i + 1 < n; ++i) {
        if (a[i] > a[i - 1] && a[i] > a[i + 1]) {
            ++peaks;
        } else if (a[i] < a[i - 1] && a[i] < a[i + 1]) {
            ++valleys;
        }
    }

    cout << peaks << ' ' << valleys << '\n';
    return 0;
}
